import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const RateTransaction = () => {
  const { transactionId } = useParams();
  const navigate = useNavigate();
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      await axios.post(`${API_URL}/ratings`, {
        transactionId,
        rating,
        comment
      });
      navigate('/customer/transactions');
    } catch (error) {
      console.error('Error submitting rating:', error);
      alert('Failed to submit rating');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
      <div style={{ maxWidth: '500px', margin: '0 auto' }}>
        <h1 style={{ fontSize: '1.75rem', fontWeight: 600, marginBottom: '2rem', color: '#212529' }}>
          Rate Your Purchase
        </h1>
        
        <form onSubmit={handleSubmit} style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', padding: '2rem' }}>
          <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
            <p style={{ color: '#6c757d', marginBottom: '1rem' }}>Transaction: {transactionId}</p>
            
            <div style={{ display: 'flex', justifyContent: 'center', gap: '0.5rem', marginBottom: '1rem' }}>
              {[1, 2, 3, 4, 5].map((star) => (
                <button
                  key={star}
                  type="button"
                  onClick={() => setRating(star)}
                  style={{
                    fontSize: '2rem',
                    background: 'none',
                    border: 'none',
                    cursor: 'pointer',
                    color: star <= rating ? '#212529' : '#dee2e6',
                    transition: 'color 0.2s ease'
                  }}
                >
                  ★
                </button>
              ))}
            </div>
          </div>

          <div style={{ marginBottom: '2rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#495057' }}>
              Comment (Optional)
            </label>
            <textarea
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              rows="4"
              style={{
                width: '100%',
                padding: '0.75rem',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '0.95rem',
                resize: 'vertical'
              }}
              placeholder="Tell us about your experience..."
            />
          </div>

          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem' }}>
            <button
              type="button"
              onClick={() => navigate('/customer/transactions')}
              style={{
                padding: '0.75rem 1.5rem',
                background: 'white',
                border: '1px solid #ced4da',
                borderRadius: '4px',
                fontSize: '0.95rem',
                color: '#495057',
                cursor: 'pointer'
              }}
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={rating === 0 || loading}
              style={{
                padding: '0.75rem 1.5rem',
                background: '#212529',
                border: 'none',
                borderRadius: '4px',
                fontSize: '0.95rem',
                color: 'white',
                cursor: rating === 0 || loading ? 'not-allowed' : 'pointer',
                opacity: rating === 0 || loading ? 0.6 : 1
              }}
            >
              {loading ? 'Submitting...' : 'Submit Rating'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default RateTransaction;
